    {
      "claim_text": "AB 3042 will provide a stable source of revenue outside the General Fund to support DNA testing programs at the local and state levels."
    },
    {
      "claim_text": "The Missing Persons DNA Program is one of the essential services provided by the Bureau of Forensic Services."
    },
    {
      "claim_text": "The Bureau of Forensic Services receives crucial funding through Proposition 69."
